package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  void beginObject_shouldReturnJsonWriterAndWriteOpeningBrace() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    // Spy on writeDeferredName and open methods
    doNothing().when(spyWriter).writeDeferredName();
    doReturn(spyWriter).when(spyWriter).open(JsonScope.EMPTY_OBJECT, '{');

    JsonWriter result = spyWriter.beginObject();

    verify(spyWriter).writeDeferredName();
    verify(spyWriter).open(JsonScope.EMPTY_OBJECT, '{');
    assertSame(spyWriter, result);
  }

  @Test
  void beginObject_realOpenAndWriteDeferredName_shouldWriteCorrectly() throws IOException {
    // We test the real behavior of beginObject including real open and writeDeferredName
    JsonWriter writer = new JsonWriter(stringWriter);

    // Use reflection to set stackSize and stack to simulate EMPTY_DOCUMENT state
    try {
      Method pushMethod = JsonWriter.class.getDeclaredMethod("push", int.class);
      pushMethod.setAccessible(true);
      pushMethod.invoke(writer, JsonScope.EMPTY_DOCUMENT);
    } catch (NoSuchMethodException | IllegalAccessException | InvocationTargetException e) {
      fail("Reflection setup failed: " + e);
    }

    JsonWriter result = writer.beginObject();

    assertSame(writer, result);
    // The output should start with '{' because beginObject calls open with '{'
    String output = stringWriter.toString();
    assertTrue(output.startsWith("{"));
  }

  @Test
  void beginObject_writeDeferredNameThrows_shouldThrowIOException() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);
    doThrow(new IOException("fail")).when(spyWriter).writeDeferredName();

    IOException thrown = assertThrows(IOException.class, spyWriter::beginObject);
    assertEquals("fail", thrown.getMessage());
  }
}

